// LESSON: Reference Page 1 - equals, hashCode, compareTo.
// You will learn: Compare identity, hashing, set uniqueness, and natural ordering.
class Prog2Reference428 {
  // EXEMPEL 1: equals jamfor logisk identitet i stallet for referens.
  static class Student {
    private final int studentId;
    Student(int studentId) { this.studentId = studentId; }
    @Override public boolean equals(Object other) {
      if (this == other) { return true; }
      if (!(other instanceof Student)) { return false; }
      Student that = (Student) other;
      return studentId == that.studentId;
    }
    @Override public int hashCode() { return Integer.hashCode(studentId); }
  }
  // EXEMPEL 2: HashSet anvander hashCode och equals for att hitta dubletter.
  static int uniqueStudents() {
    java.util.Set<Student> students = new java.util.HashSet<Student>();
    students.add(new Student(7));
    students.add(new Student(7));
    return students.size();
  }
  // EXEMPEL 3: compareTo ger en naturlig sorteringsordning.
  static class Time implements Comparable<Time> {
    private final int hour;
    private final int minute;
    Time(int hour, int minute) { this.hour = hour; this.minute = minute; }
    public int compareTo(Time other) {
      int hourOrder = Integer.compare(hour, other.hour);
      return hourOrder != 0 ? hourOrder : Integer.compare(minute, other.minute);
    }
  }
}
